<template>
 <el-card class="page-card"><div class="page-toolbar"><span class="page-note">维护系统目录、页面和按钮权限，最多支持三级结构</span><span class="spacer"></span><el-button type="primary" :icon="Plus" @click="open()">新增菜单</el-button></div><el-table :data="menus" row-key="id" default-expand-all stripe><el-table-column prop="menuName" label="菜单名称" min-width="180"/><el-table-column label="类型" width="90"><template #default="s"><el-tag :type="typeMap[s.row.menuType]?.type">{{typeMap[s.row.menuType]?.label}}</el-tag></template></el-table-column><el-table-column prop="path" label="路由路径" min-width="150"/><el-table-column prop="component" label="组件路径" min-width="180"/><el-table-column prop="permissionCode" label="权限标识" min-width="180"/><el-table-column prop="sortOrder" label="排序" width="70"/><el-table-column label="状态" width="80"><template #default="s">{{s.row.status===1?'启用':'禁用'}}</template></el-table-column><el-table-column label="操作" width="180" fixed="right"><template #default="s"><el-button link type="primary" @click="open(undefined,s.row)">新增</el-button><el-button link type="primary" @click="open(s.row)">编辑</el-button><el-button link type="danger" @click="remove(s.row)">删除</el-button></template></el-table-column></el-table></el-card>
 <el-dialog v-model="dialog" :title="form.id?'编辑菜单':'新增菜单'" width="620px"><el-form :model="form" label-width="90px"><el-row :gutter="16"><el-col :span="12"><el-form-item label="父级菜单"><el-tree-select v-model="form.parentId" :data="parentOptions" node-key="id" :props="{label:'menuName',children:'children'}" check-strictly :render-after-expand="false" style="width:100%"/></el-form-item></el-col><el-col :span="12"><el-form-item label="菜单类型"><el-radio-group v-model="form.menuType"><el-radio-button value="CATALOG">目录</el-radio-button><el-radio-button value="MENU">菜单</el-radio-button><el-radio-button value="BUTTON">按钮</el-radio-button></el-radio-group></el-form-item></el-col><el-col :span="12"><el-form-item label="菜单名称"><el-input v-model="form.menuName"/></el-form-item></el-col><el-col :span="12"><el-form-item label="图标"><el-input v-model="form.icon" placeholder="如 Setting"/></el-form-item></el-col><el-col :span="12"><el-form-item label="路由路径"><el-input v-model="form.path" :disabled="form.menuType==='BUTTON'"/></el-form-item></el-col><el-col :span="12"><el-form-item label="组件路径"><el-input v-model="form.component" :disabled="form.menuType==='BUTTON'"/></el-form-item></el-col><el-col :span="16"><el-form-item label="权限标识"><el-input v-model="form.permissionCode" placeholder="system:user:list"/></el-form-item></el-col><el-col :span="8"><el-form-item label="排序"><el-input-number v-model="form.sortOrder" :min="0"/></el-form-item></el-col><el-col :span="12"><el-form-item label="显示"><el-switch v-model="form.visible" :active-value="1" :inactive-value="0"/></el-form-item></el-col><el-col :span="12"><el-form-item label="状态"><el-switch v-model="form.status" :active-value="1" :inactive-value="0"/></el-form-item></el-col></el-row></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog>
</template>
<script setup lang="ts">import {computed,onMounted,reactive,ref} from 'vue';import {Plus} from '@element-plus/icons-vue';import {ElMessage,ElMessageBox} from 'element-plus';import {getMenuTree,createMenu,updateMenu,deleteMenu} from '@/api/system';const menus=ref<any[]>([]),dialog=ref(false);const empty=()=>({id:0,parentId:0,menuName:'',menuType:'MENU',path:'',component:'',permissionCode:'',icon:'Monitor',sortOrder:0,visible:1,status:1});const form=reactive(empty());const typeMap:any={CATALOG:{label:'目录',type:'primary'},MENU:{label:'菜单',type:'success'},BUTTON:{label:'按钮',type:'warning'}};const parentOptions=computed(()=>[{id:0,menuName:'顶级菜单',children:menus.value}]);const load=async()=>menus.value=await getMenuTree();const open=(r?:any,parent?:any)=>{Object.assign(form,empty(),r||{},parent?{parentId:parent.id}:{});dialog.value=true};const save=async()=>{if(!form.menuName)return ElMessage.warning('请输入菜单名称');form.id?await updateMenu(form.id,form):await createMenu(form);ElMessage.success('保存成功');dialog.value=false;load()};const remove=async(r:any)=>{await ElMessageBox.confirm(`确定删除“${r.menuName}”吗？`,'提示');await deleteMenu(r.id);ElMessage.success('删除成功');load()};onMounted(load)</script>
<style scoped>.page-note{color:#7d8d9c;font-size:14px}</style>
